// ========================================
// FOLDERFIX - OPTIMIZED JS
// ========================================


// ---------- NAVBAR SCROLL ----------
window.addEventListener("scroll", () => {
    const navbar = document.getElementById("mainNav");
    if (navbar) {
        navbar.classList.toggle("scrolled", window.scrollY > 50);
    }
});


// ---------- SMOOTH SCROLL ----------
document.querySelectorAll('a[href^="#"]').forEach(anchor => {
    anchor.addEventListener("click", function (e) {
        const target = document.querySelector(this.getAttribute("href"));
        const navbar = document.querySelector(".navbar");

        if (target) {
            e.preventDefault();
            const offset = target.offsetTop - (navbar ? navbar.offsetHeight : 0);

            window.scrollTo({
                top: offset,
                behavior: "smooth"
            });
        }
    });
});


// ---------- SLIDER ----------
const sliderTrack = document.getElementById("sliderTrack");

if (sliderTrack) {
    let current = 0;
    const slides = sliderTrack.querySelectorAll(".screenshot-item");
    const total = slides.length;

    const update = () => {
        sliderTrack.style.transform = `translateX(-${current * 100}%)`;
    };

    const nextBtn = document.getElementById("nextBtn");
    const prevBtn = document.getElementById("prevBtn");

    if (nextBtn) {
        nextBtn.addEventListener("click", () => {
            current = (current + 1) % total;
            update();
        });
    }

    if (prevBtn) {
        prevBtn.addEventListener("click", () => {
            current = (current - 1 + total) % total;
            update();
        });
    }

    setInterval(() => {
        current = (current + 1) % total;
        update();
    }, 5000);
}


// ---------- SCROLL REVEAL ----------
const revealElements = document.querySelectorAll(
    ".glass-card, .step-card, .testimonial-card, .pricing-card"
);

const revealOnScroll = () => {
    revealElements.forEach(el => {
        if (el.getBoundingClientRect().top < window.innerHeight - 100) {
            el.classList.add("fade-in");
        }
    });
};

window.addEventListener("scroll", revealOnScroll);
window.addEventListener("load", revealOnScroll);


// ---------- FORM VALIDATION ----------
document.querySelectorAll("form").forEach(form => {
    form.addEventListener("submit", e => {
        if (!form.checkValidity()) {
            e.preventDefault();
            e.stopPropagation();
        }
        form.classList.add("was-validated");
    });
});


// ---------- PASSWORD TOGGLE ----------
document.querySelectorAll('[data-toggle="password"]').forEach(button => {
    button.addEventListener("click", () => {

        const input = document.getElementById(button.dataset.target);
        const icon = button.querySelector("i");

        if (!input) return;

        const isPassword = input.type === "password";
        input.type = isPassword ? "text" : "password";

        if (icon) {
            icon.classList.toggle("fa-eye");
            icon.classList.toggle("fa-eye-slash");
        }
    });
});



// ---------- BUTTON LOADING ----------
document.querySelectorAll('button[type="submit"]').forEach(btn => {
    btn.addEventListener("click", () => {

        if (!btn.classList.contains("disabled")) {

            const original = btn.innerHTML;

            btn.innerHTML =
                '<i class="fas fa-spinner fa-spin me-2"></i>Loading...';

            btn.classList.add("disabled");

            setTimeout(() => {
                btn.innerHTML = original;
                btn.classList.remove("disabled");
            }, 3000);
        }
    });
});


// ---------- TOOLTIP ----------
if (typeof bootstrap !== "undefined") {
    document.querySelectorAll('[data-bs-toggle="tooltip"]').forEach(el => {
        new bootstrap.Tooltip(el);
    });
}


// ---------- AUTO HIDE TOAST ----------
setTimeout(() => {
    document.querySelectorAll(".custom-toast").forEach(el => {
        el.style.opacity = "0";
        setTimeout(() => el.remove(), 300);
    });
}, 4000);


// ---------- OTP TIMER ----------
const timerElement = document.getElementById("timer");
const resendBtn = document.getElementById("resendBtn");

if (timerElement) {

    let time = 300;

    const timer = setInterval(() => {

        time--;
        timerElement.innerText = time;

        if (time <= 0) {
            clearInterval(timer);

            if (resendBtn) {
                resendBtn.disabled = false;
            }
        }

    }, 1000);
}

